class Renderer{constructor(canvas){this._canvas=canvas;this._objects=[];this._clearColor={r:0,g:0,b:0,a:1};}
async init(){if(!navigator.gpu){throw Error("WebGPU is not supported in this browser.");}
const adapter=await navigator.gpu.requestAdapter();if(!adapter){throw Error("Couldn't request WebGPU adapter.");}
this._device=await adapter.requestDevice();this._context=this._canvas.getContext("webgpu");this._canvasFormat=navigator.gpu.getPreferredCanvasFormat();this._context.configure({device:this._device,format:this._canvasFormat,});this.resizeCanvas();window.addEventListener('resize',this.resizeCanvas.bind(this));}
resizeCanvas(){const devicePixelRatio=window.devicePixelRatio||1;const width=window.innerWidth*devicePixelRatio;const height=window.innerHeight*devicePixelRatio;this._canvas.width=width;this._canvas.height=height;this._canvas.style.width=`${window.innerWidth}px`;this._canvas.style.height=`${window.innerHeight}px`;this._canvas.style.transformOrigin="center";this.render();}
async appendSceneObject(obj){await obj.init();this._objects.push(obj);}
renderToSelectedView(outputView){for(const obj of this._objects){obj?.updateGeometry();}
let encoder=this._device.createCommandEncoder();const pass=encoder.beginRenderPass({colorAttachments:[{view:outputView,clearValue:this._clearColor,loadOp:"clear",storeOp:"store",}]});for(const obj of this._objects){obj?.render(pass);}
pass.end();const computePass=encoder.beginComputePass();for(const obj of this._objects){obj?.compute(computePass);}
computePass.end();const commandBuffer=encoder.finish();this._device.queue.submit([commandBuffer]);}
render(){this.renderToSelectedView(this._context.getCurrentTexture().createView());}}
class SceneObject{static _objectCnt=0;constructor(device,canvasFormat,shaderFile){if(this.constructor==SceneObject){throw new Error("Abstract classes can't be instantiated.");}
this._device=device;this._canvasFormat=canvasFormat;this._shaderFile=shaderFile;SceneObject._objectCnt+=1;}
getName(){return this.constructor.name+" "+SceneObject._objectCnt.toString();}
async init(){await this.createGeometry();await this.createShaders();await this.createRenderPipeline();await this.createComputePipeline();}
async createGeometry(){throw new Error("Method 'createGeometry()' must be implemented.");}
updateGeometry(){}
loadShader(filename){return new Promise((resolve,reject)=>{const xhttp=new XMLHttpRequest();xhttp.open("GET",filename);xhttp.setRequestHeader("Cache-Control","no-cache, no-store, max-age=0");xhttp.onload=function(){if(xhttp.readyState===XMLHttpRequest.DONE&&xhttp.status===200){resolve(xhttp.responseText);}
else{reject({status:xhttp.status,statusText:xhttp.statusText});}};xhttp.onerror=function(){reject({status:xhttp.status,statusText:xhttp.statusText});};xhttp.send();});}
async createShaders(){let shaderCode=await this.loadShader(this._shaderFile);this._shaderModule=this._device.createShaderModule({label:" Shader "+this.getName(),code:shaderCode,});}
async createRenderPipeline(){throw new Error("Method 'createRenderPipeline()' must be implemented.");}
render(pass){throw new Error("Method 'render(pass)' must be implemented.");}
async createComputePipeline(){throw new Error("Method 'createComputePipeline()' must be implemented.");}
compute(pass){throw new Error("Method 'compute(pass)' must be implemented.");}}
const FIRE_COLOR_BASE=[1.0,0.25,0.02];const FIRE_COLOR_TIP=[1.0,0.82,0.2];const RAIN_COLOR_DARK=[0.2,0.55,0.95];const RAIN_COLOR_LIGHT=[0.45,0.9,1.0];const INPUT_TIME_INDEX=8;const INPUT_TIME_OFFSET_BYTES=INPUT_TIME_INDEX*Float32Array.BYTES_PER_ELEMENT;class FinalProjectParticleSystemObject extends SceneObject{constructor(device,canvasFormat,shaderFile,numParticles=4096){super(device,canvasFormat,shaderFile);this._numParticles=numParticles;this._activeParticleCount=numParticles;this._step=0;this._inputData=new Float32Array(16);this._inputBuffer=this._device.createBuffer({size:this._inputData.byteLength,usage:GPUBufferUsage.UNIFORM|GPUBufferUsage.COPY_DST,});}
async init(){await this.createGeometry();await this.createShaders();await this.createRenderPipeline();await this.createComputePipeline();}
async createGeometry(){this._particles=new Float32Array(this._numParticles*12);this._particleBuffers=[this._device.createBuffer({size:this._particles.byteLength,usage:GPUBufferUsage.STORAGE|GPUBufferUsage.COPY_DST,}),this._device.createBuffer({size:this._particles.byteLength,usage:GPUBufferUsage.STORAGE|GPUBufferUsage.COPY_DST,}),];this.resetParticles();}
resetParticles(){const colorMode=Number.isFinite(this._inputData[9])?Math.max(0,Math.min(7,Math.floor(this._inputData[9]))):0;for(let i=0;i<this._numParticles;i++){const j=i*12;const x=Math.random()*2-1;const y=Math.random()*2-1;this._particles[j+0]=x;this._particles[j+1]=y;this._particles[j+2]=x;this._particles[j+3]=y;this._particles[j+4]=(Math.random()*2-1)*0.01;this._particles[j+5]=(Math.random()*2-1)*0.01;this._particles[j+6]=100+Math.random()*100;this._particles[j+7]=1.0;const[r,g,b]=this.getColorForMode(colorMode);this._particles[j+8]=r;this._particles[j+9]=g;this._particles[j+10]=b;this._particles[j+11]=1.0;}
this._device.queue.writeBuffer(this._particleBuffers[0],0,this._particles);this._step=0;}
setActiveParticleCount(count){this._activeParticleCount=Math.max(0,Math.min(this._numParticles,Math.floor(count)));}
updateInput(input){this._inputData[0]=input.x;this._inputData[1]=input.y;this._inputData[2]=input.clickMode;this._inputData[3]=input.simMode;this._inputData[4]=input.forceStrength;this._inputData[5]=input.damping;this._inputData[6]=input.particleScale;this._inputData[7]=input.trailsEnabled;const now=performance.now()/1000.0;this._inputData[INPUT_TIME_INDEX]=now;this._inputData[9]=input.colorMode||0;this._device.queue.writeBuffer(this._inputBuffer,0,this._inputData);if(typeof input.activeParticleCount==="number"){this.setActiveParticleCount(input.activeParticleCount);}
if(typeof input.consumeResetRequest==="function"?input.consumeResetRequest():input.resetRequested){this.resetParticles();}}
getColorForMode(colorMode){switch(colorMode){case 1:{const t=Math.random();return[FIRE_COLOR_BASE[0]+(FIRE_COLOR_TIP[0]-FIRE_COLOR_BASE[0])*t,FIRE_COLOR_BASE[1]+(FIRE_COLOR_TIP[1]-FIRE_COLOR_BASE[1])*t,FIRE_COLOR_BASE[2]+(FIRE_COLOR_TIP[2]-FIRE_COLOR_BASE[2])*t,];}
case 2:{const t=Math.random();return[RAIN_COLOR_DARK[0]+(RAIN_COLOR_LIGHT[0]-RAIN_COLOR_DARK[0])*t,RAIN_COLOR_DARK[1]+(RAIN_COLOR_LIGHT[1]-RAIN_COLOR_DARK[1])*t,RAIN_COLOR_DARK[2]+(RAIN_COLOR_LIGHT[2]-RAIN_COLOR_DARK[2])*t,];}
case 3:return[0.9,0.9,0.9];case 4:return[0.2,0.8,0.2];case 5:return[1.0,0.2,0.8];case 6:return[0.8,0.2,1.0];case 7:return[1.0,1.0,0.2];default:return[Math.random(),Math.random(),Math.random()];}}
async createShaders(){await super.createShaders();this._bindGroupLayout=this._device.createBindGroupLayout({entries:[{binding:0,visibility:GPUShaderStage.VERTEX|GPUShaderStage.COMPUTE,buffer:{type:"read-only-storage"},},{binding:1,visibility:GPUShaderStage.COMPUTE,buffer:{type:"storage"},},{binding:2,visibility:GPUShaderStage.VERTEX|GPUShaderStage.COMPUTE,buffer:{type:"uniform"},},],});this._pipelineLayout=this._device.createPipelineLayout({bindGroupLayouts:[this._bindGroupLayout],});}
async createRenderPipeline(){this._pipeline=this._device.createRenderPipeline({layout:this._pipelineLayout,vertex:{module:this._shaderModule,entryPoint:"vertexMain",},fragment:{module:this._shaderModule,entryPoint:"fragmentMain",targets:[{format:this._canvasFormat,}]},primitive:{topology:"triangle-list"},});this._bindGroups=[this._device.createBindGroup({layout:this._pipeline.getBindGroupLayout(0),entries:[{binding:0,resource:{buffer:this._particleBuffers[0]}},{binding:1,resource:{buffer:this._particleBuffers[1]}},{binding:2,resource:{buffer:this._inputBuffer}},],}),this._device.createBindGroup({layout:this._pipeline.getBindGroupLayout(0),entries:[{binding:0,resource:{buffer:this._particleBuffers[1]}},{binding:1,resource:{buffer:this._particleBuffers[0]}},{binding:2,resource:{buffer:this._inputBuffer}},],})];}
render(pass){pass.setPipeline(this._pipeline);pass.setBindGroup(0,this._bindGroups[this._step%2]);pass.draw(6,this._activeParticleCount);}
async createComputePipeline(){this._computePipeline=this._device.createComputePipeline({layout:this._pipelineLayout,compute:{module:this._shaderModule,entryPoint:"computeMain",}});}
compute(pass){if(this._activeParticleCount<=0){return;}
const now=performance.now()/1000.0;this._inputData[INPUT_TIME_INDEX]=now;this._device.queue.writeBuffer(this._inputBuffer,INPUT_TIME_OFFSET_BYTES,this._inputData,INPUT_TIME_INDEX,1);pass.setPipeline(this._computePipeline);pass.setBindGroup(0,this._bindGroups[this._step%2]);pass.dispatchWorkgroups(Math.ceil(this._activeParticleCount/256));this._step++;}}
class HUDButton{constructor(id,label,callback,group=null){this.id=id;this.label=label;this.callback=callback;this.group=group;this.active=false;this.element=null;}
create(){this.element=document.createElement("button");this.element.id=this.id;this.element.className="hud-button";if(this.group){this.element.classList.add(`group-${this.group}`);}
this.element.textContent=this.label;this.element.addEventListener("click",(e)=>{e.stopPropagation();this.callback();});this.element.addEventListener("mouseenter",()=>{this.element.classList.add("hover");});this.element.addEventListener("mouseleave",()=>{this.element.classList.remove("hover");});return this.element;}
setActive(active){this.active=active;if(this.element){if(active){this.element.classList.add("active");}else{this.element.classList.remove("active");}}}}
class HUDManager{constructor(hudElement,input){this.hudElement=hudElement;this.input=input;this.buttons={};this.modeButtons={};this.colorButtons={};this.showHudButton=null;this.createShowHudToggle();this.updateHUD();this.toggleHUD(this.input.hudVisible);}
updateHUD(){this.hudElement.innerHTML="";this.buttons={};this.modeButtons={};this.colorButtons={};const title=document.createElement("div");title.className="hud-title";title.innerHTML="<strong>Interactive WebGPU Particle Sandbox</strong>";this.hudElement.appendChild(title);this.createModeSection();this.createParticlesSection();this.createPropertiesSection();this.createInfoSection();this.createHideHudRow();}
createShowHudToggle(){this.showHudButton=document.createElement("button");this.showHudButton.id="show-hud-toggle";this.showHudButton.className="hud-button";this.showHudButton.textContent="Show HUD (H)";this.showHudButton.addEventListener("click",()=>{this.toggleHUD(true);});document.body.appendChild(this.showHudButton);}
createModeSection(){const section=document.createElement("div");section.className="hud-section";const header=document.createElement("div");header.className="hud-section-header";header.textContent="MODES";section.appendChild(header);const modes=[{id:"mode-1",label:"1: Static",value:1},{id:"mode-2",label:"2: Gravity",value:2},{id:"mode-3",label:"3: Explosion",value:3},{id:"mode-4",label:"4: Orbit",value:4},{id:"mode-5",label:"5: Fire",value:5},{id:"mode-6",label:"6: Rain",value:6},{id:"mode-7",label:"7: Cursor",value:7},];const buttonContainer=document.createElement("div");buttonContainer.className="hud-button-row";modes.forEach((mode)=>{const btn=new HUDButton(mode.id,mode.label,()=>{this.input.simMode=mode.value;this.updateModeHighlight();},"modes");this.modeButtons[mode.value]=btn;this.buttons[mode.id]=btn;buttonContainer.appendChild(btn.create());});section.appendChild(buttonContainer);this.hudElement.appendChild(section);this.updateModeHighlight();}
updateModeHighlight(){Object.entries(this.modeButtons).forEach(([value,btn])=>{btn.setActive(this.input.simMode===parseInt(value));});}
createParticlesSection(){const section=document.createElement("div");section.className="hud-section";const header=document.createElement("div");header.className="hud-section-header";header.textContent="PARTICLES";section.appendChild(header);const countRow=document.createElement("div");countRow.className="hud-control-row";countRow.appendChild(this.createLabel("Particle Count:"));countRow.appendChild(new HUDButton("particle-count-dec","-",()=>{this.changeParticleCount(-1);}).create());const countValue=document.createElement("span");countValue.id="particle-count-value";countValue.className="hud-value";countValue.textContent=this.input.activeParticleCount.toString();countRow.appendChild(countValue);countRow.appendChild(new HUDButton("particle-count-inc","+",()=>{this.changeParticleCount(1);}).create());section.appendChild(countRow);const sizeRow=document.createElement("div");sizeRow.className="hud-control-row";sizeRow.appendChild(this.createLabel("Particle Size:"));sizeRow.appendChild(new HUDButton("size-dec","[",()=>{this.input.particleScale=Math.max(this.input.particleScale-0.1,1.0);this.updateValues();}).create());const sizeValue=document.createElement("span");sizeValue.id="size-value";sizeValue.className="hud-value";sizeValue.textContent=this.input.particleScale.toFixed(1);sizeRow.appendChild(sizeValue);sizeRow.appendChild(new HUDButton("size-inc","]",()=>{this.input.particleScale=Math.min(this.input.particleScale+0.1,5.0);this.updateValues();}).create());section.appendChild(sizeRow);const colorsRow=document.createElement("div");colorsRow.className="hud-control-row hud-control-stack";const colorsLabel=this.createLabel("Colors:");colorsLabel.classList.add("hud-label-full");colorsRow.appendChild(colorsLabel);const colorButtonContainer=document.createElement("div");colorButtonContainer.className="colors-row";const colors=[{id:"color-0",label:"Rainbow",value:0},{id:"color-1",label:"Fire",value:1},{id:"color-2",label:"Blue",value:2},{id:"color-3",label:"White",value:3},{id:"color-4",label:"Green",value:4},{id:"color-5",label:"Pink",value:5},{id:"color-6",label:"Purple",value:6},{id:"color-7",label:"Yellow",value:7},];colors.forEach((color)=>{const btn=new HUDButton(color.id,color.label,()=>{this.input.colorMode=color.value;this.updateColorHighlight();},"colors");this.colorButtons[color.value]=btn;this.buttons[color.id]=btn;colorButtonContainer.appendChild(btn.create());});colorsRow.appendChild(colorButtonContainer);section.appendChild(colorsRow);const utilityRow=document.createElement("div");utilityRow.className="hud-control-row hud-control-stack";const utilityLabel=this.createLabel("Utility:");utilityLabel.classList.add("hud-label-full");utilityRow.appendChild(utilityLabel);const utilityButtons=document.createElement("div");utilityButtons.className="hud-button-row utility-buttons";utilityButtons.appendChild(new HUDButton("trails-toggle","T: Trails OFF",()=>{this.input.trailsEnabled=this.input.trailsEnabled?0:1;this.updateValues();}).create());utilityButtons.appendChild(new HUDButton("reset-particles","R: Reset",()=>{this.input.resetParticles();this.updateValues();}).create());utilityRow.appendChild(utilityButtons);section.appendChild(utilityRow);this.hudElement.appendChild(section);this.updateColorHighlight();}
createPropertiesSection(){const section=document.createElement("div");section.className="hud-section";const header=document.createElement("div");header.className="hud-section-header";header.textContent="PROPERTIES";section.appendChild(header);const forceRow=document.createElement("div");forceRow.className="hud-control-row";forceRow.appendChild(this.createLabel("Force Strength:"));forceRow.appendChild(new HUDButton("force-dec","↓",()=>{this.input.forceStrength=Math.max(this.input.forceStrength-0.0002,0.0002);this.updateValues();}).create());const forceValue=document.createElement("span");forceValue.id="force-value";forceValue.className="hud-value";forceValue.textContent=this.input.forceStrength.toFixed(4);forceRow.appendChild(forceValue);forceRow.appendChild(new HUDButton("force-inc","↑",()=>{this.input.forceStrength=Math.min(this.input.forceStrength+0.0002,0.01);this.updateValues();}).create());section.appendChild(forceRow);const dampingRow=document.createElement("div");dampingRow.className="hud-control-row";dampingRow.appendChild(this.createLabel("Damping:"));dampingRow.appendChild(new HUDButton("damping-dec","←",()=>{this.input.damping=Math.max(this.input.damping-0.001,0.96);this.updateValues();}).create());const dampingValue=document.createElement("span");dampingValue.id="damping-value";dampingValue.className="hud-value";dampingValue.textContent=this.input.damping.toFixed(3);dampingRow.appendChild(dampingValue);dampingRow.appendChild(new HUDButton("damping-inc","→",()=>{this.input.damping=Math.min(this.input.damping+0.001,0.999);this.updateValues();}).create());section.appendChild(dampingRow);this.hudElement.appendChild(section);}
createHideHudRow(){const hideRow=document.createElement("div");hideRow.className="hud-control-row hud-bottom-row";hideRow.appendChild(new HUDButton("hide-hud","H: Hide HUD",()=>{this.toggleHUD(false);}).create());this.hudElement.appendChild(hideRow);}
createLabel(text){const label=document.createElement("span");label.className="hud-label";label.textContent=text;return label;}
createInfoSection(){const section=document.createElement("div");section.className="hud-section hud-info";const info=document.createElement("div");info.innerHTML=`<small><strong>Mouse:</strong> Left Click = Attract | Right Click = Repel<br/><strong>Keyboard:</strong> 1-7 = Modes | ↑↓ = Force | ←→ = Damping<br/><strong>Shortcuts:</strong> [ Smaller | ] Bigger | -/+ = Count | T = Trails | R = Reset | H = Toggle HUD</small>`;section.appendChild(info);this.hudElement.appendChild(section);}
changeParticleCount(delta){const nextCount=this.input.activeParticleCount+delta;this.input.activeParticleCount=Math.max(0,Math.min(Math.floor(nextCount),this.input.maxActiveParticles));this.updateValues();}
toggleHUD(forceVisible){const visible=typeof forceVisible==="boolean"?forceVisible:!this.input.hudVisible;this.input.hudVisible=visible;this.hudElement.style.display=visible?"block":"none";if(this.showHudButton){this.showHudButton.style.display=visible?"none":"block";}}
updateValues(){const sizeValue=document.getElementById("size-value");const particleCountValue=document.getElementById("particle-count-value");const forceValue=document.getElementById("force-value");const dampingValue=document.getElementById("damping-value");const trailsBtn=document.getElementById("trails-toggle");if(sizeValue)sizeValue.textContent=this.input.particleScale.toFixed(1);if(particleCountValue)particleCountValue.textContent=this.input.activeParticleCount.toString();if(forceValue)forceValue.textContent=this.input.forceStrength.toFixed(4);if(dampingValue)dampingValue.textContent=this.input.damping.toFixed(3);if(trailsBtn)trailsBtn.textContent=`T: Trails ${this.input.trailsEnabled ? "ON" : "OFF"}`;this.updateModeHighlight();this.updateColorHighlight();}
updateColorHighlight(){Object.entries(this.colorButtons).forEach(([value,btn])=>{btn.setActive(this.input.colorMode===parseInt(value));});}
refresh(){this.updateValues();this.toggleHUD(this.input.hudVisible);}}
HUDManager;const MAX_ACTIVE_PARTICLE_COUNT=999;async function init(){const canvas=document.createElement("canvas");canvas.id="renderCanvas";document.body.appendChild(canvas);const hud=document.createElement("div");hud.id="hud";document.body.appendChild(hud);const renderer=new Renderer(canvas);await renderer.init();const particles=new FinalProjectParticleSystemObject(renderer._device,renderer._canvasFormat,"./lib/Shaders/optimized_finalprojectparticles.wgsl",4096);await renderer.appendSceneObject(particles);const input={x:0,y:0,clickMode:0,simMode:1,forceStrength:0.002,damping:0.992,particleScale:1.0,trailsEnabled:0,colorMode:0,maxActiveParticles:MAX_ACTIVE_PARTICLE_COUNT,activeParticleCount:333,hudVisible:true,resetRequested:false,};input.resetParticles=()=>{input.resetRequested=true;};input.consumeResetRequest=()=>{const requested=input.resetRequested;input.resetRequested=false;return requested;};const hudManager=new HUDManager(hud,input);canvas.addEventListener("mousemove",(e)=>{input.x=(e.clientX/window.innerWidth)*2-1;input.y=(-e.clientY/window.innerHeight)*2+1;});canvas.addEventListener("mousedown",(e)=>{if(e.button===0)input.clickMode=1;if(e.button===2)input.clickMode=2;});canvas.addEventListener("mouseup",()=>{input.clickMode=0;});canvas.addEventListener("mouseleave",()=>{input.clickMode=0;});canvas.addEventListener("contextmenu",(e)=>{e.preventDefault();});window.addEventListener("keydown",(e)=>{let changed=false;switch(e.key){case"1":input.simMode=1;changed=true;break;case"2":input.simMode=2;changed=true;break;case"3":input.simMode=3;changed=true;break;case"4":input.simMode=4;changed=true;break;case"5":input.simMode=5;changed=true;break;case"6":input.simMode=6;changed=true;break;case"7":input.simMode=7;changed=true;break;case"ArrowUp":input.forceStrength=Math.min(input.forceStrength+0.0002,0.01);changed=true;break;case"ArrowDown":input.forceStrength=Math.max(input.forceStrength-0.0002,0.0002);changed=true;break;case"ArrowRight":input.damping=Math.min(input.damping+0.001,0.999);changed=true;break;case"ArrowLeft":input.damping=Math.max(input.damping-0.001,0.96);changed=true;break;case"[":input.particleScale=Math.max(input.particleScale-0.1,1.0);changed=true;break;case"]":input.particleScale=Math.min(input.particleScale+0.1,5.0);changed=true;break;case"t":case"T":input.trailsEnabled=input.trailsEnabled?0:1;changed=true;break;case"r":case"R":input.resetParticles();changed=true;break;case"h":case"H":input.hudVisible=!input.hudVisible;changed=true;break;case"-":input.activeParticleCount=Math.max(input.activeParticleCount-1,0);changed=true;break;case"+":case"=":input.activeParticleCount=Math.min(input.activeParticleCount+1,input.maxActiveParticles);changed=true;break;}
if(changed){hudManager.refresh();}});function loop(){particles.updateInput(input);renderer.render();requestAnimationFrame(loop);}
loop();}
init().catch((e)=>{const p=document.createElement("p");p.innerHTML=navigator.userAgent+"<br/>"+e.message;document.body.appendChild(p);});